using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Shared notebook for the note-taking tool
var notebook = new Notebook();

// Define the agent's tools
var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWeb, "SearchWeb",
        "Searches the web for information on a given query. Returns a list of results with titles, snippets, and URLs."),

    AIFunctionFactory.Create(notebook.TakeNote, "TakeNote",
        "Saves a research note. Use this to record important findings, key facts, or insights discovered during research."),

    AIFunctionFactory.Create(notebook.GetNotes, "GetNotes",
        "Retrieves all saved research notes from the notebook."),
};

// Build the chat client via the MEAI abstraction
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Create the research agent
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to thoroughly research a topic provided by the user.

        Follow this process:
        1. Search the web for information on the topic using multiple targeted queries.
        2. Take notes on the most important findings using the TakeNote tool.
        3. After gathering enough information, retrieve your notes with GetNotes and
           synthesize them into a well-structured summary.

        Always cite your sources. Be thorough but concise in your final summary.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes",
    tools: tools);

// Get the topic from the user
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// Run the agent with streaming output
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

await foreach (var update in agent.RunStreamingAsync(topic, options: runOptions))
{
    if (update.Text is { } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine("\n\n--- Research Complete ---");

if (notebook.Count > 0)
{
    Console.WriteLine("\n📝 Saved Notes:");
    foreach (var (id, note) in notebook.AllNotes)
    {
        Console.WriteLine($"  {id}. {note}");
    }
}

// --- Tool implementations ---------------------------------------------------

static IReadOnlyList<SearchResult> SearchWeb(
    [System.ComponentModel.Description("The search query to look up on the web")]
    string query)
{
    // Simulated web search results for demonstration.
    // Replace this with a real search API (e.g., Bing Search) for production use.
    var slug = query.Replace(' ', '-').ToLowerInvariant();
    return
    [
        new($"Overview of {query}",
            $"A comprehensive overview covering the key aspects of {query}, including history, current state, and future outlook.",
            $"https://example.com/overview-{slug}"),

        new($"{query} — Latest Research",
            $"Recent research findings and developments related to {query}. Experts weigh in on the most important trends.",
            $"https://example.com/research-{slug}"),

        new($"Understanding {query}: A Deep Dive",
            $"An in-depth analysis of {query} examining multiple perspectives and providing actionable insights.",
            $"https://example.com/deep-dive-{slug}"),
    ];
}

// --- Supporting types --------------------------------------------------------

record SearchResult(string Title, string Snippet, string Url);

/// <summary>Thread-safe notebook that stores research notes.</summary>
sealed class Notebook
{
    private readonly System.Collections.Concurrent.ConcurrentDictionary<int, string> _notes = new();
    private int _nextId;

    public int Count => _notes.Count;

    public IEnumerable<KeyValuePair<int, string>> AllNotes =>
        _notes.OrderBy(kv => kv.Key);

    public object TakeNote(
        [System.ComponentModel.Description("Short title for the note")]
        string title,
        [System.ComponentModel.Description("The content/body of the note")]
        string content)
    {
        var id = Interlocked.Increment(ref _nextId);
        _notes[id] = $"[{title}] {content}";
        return new { NoteId = id, Status = "Saved", Title = title };
    }

    public string GetNotes()
    {
        if (_notes.IsEmpty)
            return "No notes have been saved yet.";

        return string.Join('\n', _notes.OrderBy(kv => kv.Key)
            .Select(kv => $"Note {kv.Key}: {kv.Value}"));
    }
}

